type Cell = [number, number]; // [x, y]

export function nextGeneration(cells: Cell[]): Cell[] {
  const living = new Set(cells.map(([x, y]) => `${x},${y}`));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }

  const next: Cell[] = [];
  for (const [key, count] of neighborCounts) {
    const isAlive = living.has(key);
    if (count === 3 || (isAlive && count === 2)) {
      const [x, y] = key.split(",").map(Number);
      next.push([x, y]);
    }
  }

  return next;
}

import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - Next Generation", () => {
  // Degenerate cases
  it("an empty grid stays empty", () => {
    expect(nextGeneration([])).toEqual([]);
  });
  it("a single live cell dies (underpopulation)", () => {
    expect(nextGeneration([[0, 0]])).toEqual([]);
  });

  // Rule 1 - Underpopulation
  it.todo("two adjacent live cells both die (each has 1 neighbor)");

  // Rule 4 - Reproduction
  it("a dead cell with exactly 3 live neighbors becomes alive", () => {
    const next = nextGeneration([
      [0, 0],
      [1, 0],
      [0, 1],
    ]);
    expect(next).toContainEqual([1, 1]);
  });

  // Rule 2 - Survival
  it.todo("a live cell with 2 or 3 live neighbors survives");

  // Rule 3 - Overpopulation
  it.todo("a live cell with more than 3 live neighbors dies");

  // Negative coordinates
  it.todo("handles negative coordinates");

  // Pattern examples
  it.todo("blinker oscillates from vertical to horizontal");
  it.todo("block still life remains unchanged");
});

